// Patched server entry - adds HEAD API interceptor before TanStack SSR
import { createServer } from 'node:http'
import { readFile, stat } from 'node:fs/promises'
import { join, extname } from 'node:path'
import { fileURLToPath } from 'node:url'
import server from '/app/dist/server/server.js'

const __dirname = fileURLToPath(new URL('.', import.meta.url))
const CLIENT_DIR = join(__dirname, 'dist', 'client')
const port = parseInt(process.env.PORT || '3000', 10)
const host = process.env.HOST || '127.0.0.1'

function isNonLoopbackHost(h) {
  if (!h) return false
  const norm = h.trim().toLowerCase()
  if (norm === '127.0.0.1' || norm === '::1' || norm === 'localhost') return false
  return true
}

if (isNonLoopbackHost(host)) {
  const password: [REDACTED] || process.env.CLAUDE_PASSWORD || '').trim()
  if (!password) {
    console.error('\n[workspace] refusing to start.\n  HOST is set to "' + host + '" (non-loopback), but HERMES_PASSWORD is unset.\n')
    const allowInsecure = (process.env.HERMES_ALLOW_INSECURE_REMOTE || process.env.CLAUDE_ALLOW_INSECURE_REMOTE || '').trim().toLowerCase()
    if (allowInsecure !== '1' && allowInsecure !== 'true' && allowInsecure !== 'yes') process.exit(1)
    console.warn('[workspace] HERMES_ALLOW_INSECURE_REMOTE is set.')
  }
}

const MIME_TYPES = {
  '.js': 'application/javascript', '.mjs': 'application/javascript', '.css': 'text/css',
  '.html': 'text/html', '.json': 'application/json', '.svg': 'image/svg+xml',
  '.png': 'image/png', '.jpg': 'image/jpeg', '.ico': 'image/x-icon',
}

async function tryServeStatic(req, res) {
  const url = new URL(req.url || '/', `http://${req.headers.host || 'localhost'}`)
  const pathname = decodeURIComponent(url.pathname)
  if (pathname.includes('..')) return false
  if (pathname.startsWith('/assets/')) {
    const fp = join(CLIENT_DIR, pathname)
    if (!fp.startsWith(CLIENT_DIR)) return false
    try { const s = await stat(fp); if (!s.isFile()) throw Error(); } catch { res.writeHead(404, { 'Content-Type': 'text/plain' }); res.end('Asset not found'); return true }
  }
  const fp = join(CLIENT_DIR, pathname)
  if (!fp.startsWith(CLIENT_DIR)) return false
  try {
    const s = await stat(fp)
    if (!s.isFile()) return false
    const data = await readFile(fp)
    res.writeHead(200, { 'Content-Type': MIME_TYPES[extname(fp).toLowerCase()] || 'application/octet-stream', 'Content-Length': data.length })
    res.end(data)
    return true
  } catch { return false }
}

async function handler(req, res) {
  if (req.method === 'GET' || req.method === 'HEAD') {
    if (await tryServeStatic(req, res)) return
  }
  const path = new URL(req.url || '/', `http://${req.headers.host || 'localhost'}`).pathname
  // FIX: HEAD /api/* returns empty 401 instead of HTML shell
  if (req.method === 'HEAD' && path.startsWith('/api/')) {
    res.writeHead(401, { 'Content-Type': 'application/json' })
    res.end()
    return
  }
  const url = new URL(req.url || '/', `http://${req.headers.host || 'localhost'}`)
  const headers = new Headers()
  for (const [k, v] of Object.entries(req.headers)) if (v) headers.set(k, Array.isArray(v) ? v.join(', ') : v)
  let body = null
  if (req.method !== 'GET' && req.method !== 'HEAD') {
    body = await new Promise(r => { const c = []; req.on('data', d => c.push(d)); req.on('end', () => r(Buffer.concat(c))) })
  }
  try {
    const resp = await server.fetch(new Request(url.toString(), { method: req.method, headers, body, duplex: 'half' }))
    res.writeHead(resp.status, Object.fromEntries(resp.headers.entries()))
    if (resp.body) {
      const reader = resp.body.getReader()
      const pump = async () => { while (true) { const { done, value } = await reader.read(); if (done) break; res.write(value) } res.end() }
      pump().catch(e => { console.error('Stream error:', e); res.end() })
    } else { res.end(await resp.text()) }
  } catch (e) { console.error('Error:', e); res.writeHead(500); res.end('Internal Server Error') }
}

function listen(b) { createServer(handler).listen(port, b, () => console.log(`Workspace at http://${b}:${port}`)) }
listen(host)
if (host === '127.0.0.1') listen('::1')
